import yaml
import os

compose_files = [
    '/workspace/compose.yaml',
    '/workspace/compose.override.yaml',
    '/workspace/compose.production.yaml',
    '/workspace/compose.staging.yaml',
    '/workspace/compose.infogami-local.yaml',
    '/workspace/scripts/solr_builder/compose.yaml'
]

print("Checking SOLR max.booleanClauses across all compose files:\n")

for filepath in compose_files:
    if not os.path.exists(filepath):
        print(f"⚠ {filepath}: File not found")
        continue

    try:
        with open(filepath) as f:
            data = yaml.safe_load(f)

        if not data or 'services' not in data:
            print(f"⚠ {filepath}: No services defined")
            continue

        # Look for solr service
        if 'solr' in data['services']:
            solr_service = data['services']['solr']
            if 'environment' in solr_service:
                solr_opts_var = next((var for var in solr_service['environment'] if isinstance(var, str) and var.startswith("SOLR_OPTS=")), None)
                if solr_opts_var:
                    solr_opts = solr_opts_var.split("=", 1)[1]
                    matches = [opt for opt in solr_opts.split() if opt.startswith("-Dsolr.max.booleanClauses")]
                    if matches:
                        value = int(matches[0].split("=", 1)[1])
                        print(f"✓ {filepath}: {value}")
                    else:
                        print(f"⚠ {filepath}: No max.booleanClauses setting found")
                else:
                    print(f"⚠ {filepath}: No SOLR_OPTS environment variable")
            else:
                print(f"⚠ {filepath}: No environment defined for solr service")
        else:
            print(f"⚠ {filepath}: No solr service defined")
    except Exception as e:
        print(f"✗ {filepath}: Error - {e}")

