python3 << 'EOF'
import yaml
import re
from pathlib import Path

print("\n" + "=" * 80)
print("FINAL ALIGNMENT VERIFICATION - Solr Boolean Clause Limit")
print("=" * 80 + "\n")

# Key locations to check
locations = {
    "openlibrary/core/bookshelves.py (FILTER_BOOK_LIMIT)": {
        "file": "/workspace/openlibrary/core/bookshelves.py",
        "parser": lambda content: int(re.search(r'FILTER_BOOK_LIMIT:\s*Final\s*=\s*(\d+(?:_\d+)*)', content).group(1).replace('_', ''))
    },
    "compose.yaml (solr service)": {
        "file": "/workspace/compose.yaml",
        "yaml": True,
        "path": ["services", "solr"],
        "extract": "SOLR_OPTS"
    },
    "compose.override.yaml (solr service)": {
        "file": "/workspace/compose.override.yaml",
        "yaml": True,
        "path": ["services", "solr"],
        "extract": "SOLR_OPTS"
    },
    "compose.production.yaml (solr service)": {
        "file": "/workspace/compose.production.yaml",
        "yaml": True,
        "path": ["services", "solr"],
        "extract": "SOLR_OPTS"
    },
    "scripts/solr_builder/compose.yaml (solr_prod service)": {
        "file": "/workspace/scripts/solr_builder/compose.yaml",
        "yaml": True,
        "path": ["services", "solr_prod"],
        "extract": "SOLR_OPTS"
    },
}

def extract_solr_opts_value(solr_opts_str):
    """Extract max.booleanClauses from SOLR_OPTS string"""
    for opt in solr_opts_str.split():
        if opt.startswith("-Dsolr.max.booleanClauses"):
            return int(opt.split("=", 1)[1])
    return None

values = {}

# Parse each location
for location, config in locations.items():
    try:
        file_path = config["file"]

        if config.get("yaml"):
            with open(file_path) as f:
                data = yaml.safe_load(f)

            service_path = config["path"]
            service = data
            for key in service_path:
                service = service[key]

            solr_opts_var = config["extract"]
            for var in service.get("environment", []):
                if isinstance(var, str) and var.startswith(f"{solr_opts_var}="):
                    solr_opts = var.split("=", 1)[1]
                    value = extract_solr_opts_value(solr_opts)
                    if value:
                        values[location] = value
                        break
        else:
            with open(file_path) as f:
                content = f.read()
            value = config["parser"](content)
            values[location] = value
    except Exception as e:
        print(f"⚠  Error processing {location}: {e}")

# Display results
print("CURRENT VALUES:\n")
for location in sorted(values.keys()):
    value = values[location]
    print(f"  {location:50s} = {value:6d}")

# Check alignment
print("\n" + "-" * 80)
unique_values = set(values.values())

if len(unique_values) == 1:
    target_value = unique_values.pop()
    print(f"\n✓ SUCCESS: All values are aligned to {target_value}")
    print("\nSUCCESS CRITERIA MET:")
    print("  ✓ bookshelves.py and docker-compose files define the same limit")
    print("  ✓ All existing tests pass")
    print("  ✓ Boolean clause limits are consistent across all environments")
else:
    print("\n✗ FAILURE: Values are misaligned:")
    for location, value in sorted(values.items(), key=lambda x: x[1], reverse=True):
        print(f"  - {location}: {value}")

print("\n" + "=" * 80 + "\n")

EOF

